-- ملء محتوى عنقود "الأذكار والأدعية" (adhkar-adiya) — خمسة تصنيفات
-- فرعية draft بالكامل: أذكار اليوم والليلة، أذكار المناسبات والأحوال،
-- أدعية القرآن والسنة، الرقية الشرعية، فقه الدعاء والذكر.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دفعة seerah-nabawiyya (تعريفي موجز:
-- قسم body + قسم examples).
-- المصادر المعتمدة: الأذكار للنووي (أذكار اليوم والليلة)، حصن المسلم
-- من أذكار الكتاب والسنة للقحطاني (أذكار المناسبات والأحوال)، الكلم
-- الطيب لشيخ الإسلام ابن تيمية (أدعية القرآن والسنة)، زاد المعاد لابن
-- قيم الجوزية (الرقية الشرعية)، الوابل الصيب من الكلم الطيب لابن قيم
-- الجوزية (فقه الدعاء والذكر).
-- خمسة أحاديث استُشهد بها، تحقَّقت حرفياً عبر WebSearch قبل الإدراج:
-- «من قال حين يصبح وحين يمسي: سبحان الله وبحمده مائة مرة...» عن أبي
-- هريرة (رواه مسلم 2692)، دعاء السفر عن ابن عمر (رواه مسلم 1342)،
-- «كان أكثر دعاء النبي: اللهم ربنا آتنا في الدنيا حسنة...» عن أنس
-- (متفق عليه، البخاري 6389 ومسلم 2690)، «كان إذا اشتكى يقرأ على نفسه
-- بالمعوذات وينفث» عن عائشة (متفق عليه، البخاري 5016 ومسلم 2192)،
-- «مثل الذي يذكر ربه والذي لا يذكر ربه مثل الحي والميت» عن أبي موسى
-- الأشعري (متفق عليه، البخاري 6407 ومسلم 779).
-- آيتان تحقَّقتا حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: البقرة 201 (ربنا آتنا في الدنيا حسنة)،
-- الزخرف 13-14 (سبحان الذي سخر لنا هذا)، مضمّنة في نص دعاء السفر.
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الخمسة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) أذكار اليوم والليلة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='3db0bab4-eaa0-4000-b7f6-53c8d0e11e6f' AND title='أذكار اليوم والليلة: التسبيح الصباحي والمسائي أنموذجًا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أذكار اليوم والليلة: التسبيح الصباحي والمسائي أنموذجًا', 'تعريف موجز بعلم أذكار اليوم والليلة، والتسبيح الصباحي والمسائي أنموذجًا للأذكار الجامعة', '3db0bab4-eaa0-4000-b7f6-53c8d0e11e6f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أذكار اليوم والليلة علم مستقل جمعه النووي، والتسبيح الصباحي والمسائي أنموذج جامع', 'أذكار اليوم والليلة علم مستقل يُعنى بترتيب ما ورد من أذكار وأدعية مخصوصة لأوقات اليوم والليلة المختلفة، وأشهر من صنّف فيه الإمام أبو زكريا يحيى بن شرف النووي في كتابه "الأذكار" (الأذكار المنتخب من كلام سيد الأبرار)، الذي جمع فيه ما صحّ من هذه الأذكار مستدلاً بالقرآن والسنة. ومن أبرز هذه الأذكار التسبيح المطلق الذي لا يتقيد بمناسبة معينة بل يُقال في طرفي النهار طلبًا للأجر العظيم المرتب عليه، وهو من الأذكار الجامعة القصيرة اللفظ العظيمة الأجر، مما يجعله نموذجًا متكررًا في أبواب أذكار الصباح والمساء عند النووي وغيره.', 1),
    (v_lesson, 'examples', 'فضل التسبيح مائة مرة صباحًا ومساءً', 'عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «من قال حين يصبح وحين يمسي: سبحان الله وبحمده، مائة مرة، لم يأت أحد يوم القيامة بأفضل مما جاء به إلا أحد قال مثل ما قال أو زاد عليه» (رواه مسلم 2692). وهذا الحديث نموذج لما تضمنه كتاب الأذكار للنووي من فضائل الأذكار اليسيرة اللفظ العظيمة الثواب، إذ يجمع بين سهولة الترديد وعظم الأجر المترتب عليه في ميزان يوم القيامة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الأذكار — أبو زكريا يحيى بن شرف النووي', 1);
  END IF;

  -- 2) أذكار المناسبات والأحوال
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f8c99ce7-6961-4a21-91d1-2688c3cc6f98' AND title='أذكار المناسبات والأحوال: دعاء السفر أنموذجًا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أذكار المناسبات والأحوال: دعاء السفر أنموذجًا', 'تعريف موجز بأذكار المناسبات والأحوال المتنوعة، ودعاء السفر أنموذجًا لها', 'f8c99ce7-6961-4a21-91d1-2688c3cc6f98', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أذكار المناسبات والأحوال باب واسع رتّبه القحطاني، ودعاء السفر أنموذج له', 'أذكار المناسبات والأحوال باب واسع من أبواب الذكر يشمل ما ورد من أدعية مخصوصة لكل مناسبة أو حال يمر بها المسلم كالسفر والمرض والغضب والفرح، جمعها الشيخ سعيد بن علي بن وهف القحطاني في كتابه "حصن المسلم من أذكار الكتاب والسنة" مرتبةً بحسب المناسبة ومستقاة من الأحاديث الصحيحة. ومن أبرز أذكار الأحوال دعاء السفر، الذي كان النبي صلى الله عليه وسلم يحرص عليه عند كل خروج، جامعًا بين تسبيح مأخوذ من القرآن الكريم ودعاء بسؤال الله البر والتقوى في السفر.', 1),
    (v_lesson, 'examples', 'دعاء السفر عن ابن عمر رضي الله عنهما', 'عن عبد الله بن عمر رضي الله عنهما أن رسول الله صلى الله عليه وسلم كان إذا استوى على بعيره خارجًا إلى سفر كبّر ثلاثًا، ثم قال: «سبحان الذي سخّر لنا هذا وما كنا له مقرنين، وإنا إلى ربنا لمنقلبون، اللهم إنا نسألك في سفرنا هذا البر والتقوى، ومن العمل ما ترضى» (رواه مسلم 1342). وأول هذا الدعاء اقتباس من قوله تعالى: ﴿لِتَسْتَوُوا عَلَىٰ ظُهُورِهِ ثُمَّ تَذْكُرُوا نِعْمَةَ رَبِّكُمْ إِذَا اسْتَوَيْتُمْ عَلَيْهِ وَتَقُولُوا سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَٰذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ * وَإِنَّا إِلَىٰ رَبِّنَا لَمُنقَلِبُونَ﴾ (الزخرف: 13-14)، وهو نموذج لكيفية استمداد أذكار الأحوال من القرآن والسنة معًا.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'حصن المسلم من أذكار الكتاب والسنة — سعيد بن علي بن وهف القحطاني', 1);
  END IF;

  -- 3) أدعية القرآن والسنة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='de154271-d581-43fb-b57c-6f0ea5a5a1c8' AND title='أدعية القرآن والسنة: ربنا آتنا في الدنيا حسنة أنموذجًا للدعاء الجامع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أدعية القرآن والسنة: ربنا آتنا في الدنيا حسنة أنموذجًا للدعاء الجامع', 'تعريف موجز بالأدعية المأثورة من القرآن والسنة، والدعاء الجامع ربنا آتنا في الدنيا حسنة أنموذجًا', 'de154271-d581-43fb-b57c-6f0ea5a5a1c8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أدعية القرآن والسنة جمعها ابن تيمية، والدعاء الجامع نموذجها الأبرز', 'باب الأدعية المأثورة من القرآن والسنة هو ما توارد ذكره في كتاب الله على ألسنة الأنبياء والصالحين، أو ثبت عن النبي صلى الله عليه وسلم من الدعاء، وقد جمع طائفة واسعة منها شيخ الإسلام أحمد بن تيمية في كتابه "الكلم الطيب"، معتنيًا بصحة نسبتها إلى مصادرها. ومن أجمع هذه الأدعية دعاء "ربنا آتنا في الدنيا حسنة وفي الآخرة حسنة وقنا عذاب النار"، وهو دعاء قرآني ورد على لسان المؤمنين في سورة البقرة، وكان من أكثر ما يدعو به النبي صلى الله عليه وسلم، لجمعه خيري الدنيا والآخرة والوقاية من النار في عبارة موجزة جامعة.', 1),
    (v_lesson, 'examples', 'الدعاء الجامع في القرآن وحرص النبي عليه في السنة', 'قال تعالى: ﴿وَمِنْهُم مَّن يَقُولُ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ﴾ (البقرة: 201). وعن أنس بن مالك رضي الله عنه قال: «كان أكثر دعاء النبي صلى الله عليه وسلم: اللهم ربنا آتنا في الدنيا حسنة وفي الآخرة حسنة وقنا عذاب النار» (متفق عليه، رواه البخاري 6389 ومسلم 2690)، فجمع صلى الله عليه وسلم بين الدعاء بالآية القرآنية والمواظبة عليها في سنته، نموذجًا لاتصال أدعية القرآن بأدعية السنة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الكلم الطيب — تقي الدين أحمد بن تيمية', 1);
  END IF;

  -- 4) الرقية الشرعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f575aad1-4aba-4b64-9206-994b5da0b83c' AND title='الرقية الشرعية: رقية النبي صلى الله عليه وسلم نفسه بالمعوذات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الرقية الشرعية: رقية النبي صلى الله عليه وسلم نفسه بالمعوذات', 'تعريف موجز بالرقية الشرعية وشروطها، ورقية النبي صلى الله عليه وسلم نفسه بالمعوذات أنموذجًا', 'f575aad1-4aba-4b64-9206-994b5da0b83c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الرقية الشرعية بيّن أحكامها ابن القيم في زاد المعاد، ورقية النبي نفسه أعظم أدلتها', 'الرقية الشرعية هي التداوي بالقراءة والدعاء المأثور طلبًا للشفاء من الله، وهي جائزة بل مستحبة إذا خلت من الشرك واقتصرت على كلام الله وأسمائه وصفاته أو الأدعية المأثورة بلسان عربي مفهوم المعنى، كما فصّل ذلك ابن قيم الجوزية في كتابه "زاد المعاد في هدي خير العباد" ضمن قسمه الواسع في الطب النبوي، مبيّنًا أدلتها من فعل النبي صلى الله عليه وسلم نفسه وإقراره لأصحابه. وقد كان صلى الله عليه وسلم يرقي نفسه بالمعوذات (سورتي الفلق والناس) عند المرض، وهو من أعظم الأدلة على مشروعيتها.', 1),
    (v_lesson, 'examples', 'رقية النبي نفسه بالمعوذات عند المرض', 'عن عائشة رضي الله عنها: «كان النبي صلى الله عليه وسلم إذا اشتكى يقرأ على نفسه بالمعوذات وينفث، فلما اشتد وجعه كنت أقرأ عليه وأمسح بيده رجاء بركتها» (متفق عليه، رواه البخاري 5016 ومسلم 2192). ووصف الزهري النفث بأنه القراءة على اليدين ثم المسح بهما على الوجه والجسد، وهو نموذج تطبيقي لكيفية الرقية الذاتية التي أوردها ابن القيم في زاد المعاد ضمن هدي النبي صلى الله عليه وسلم في التداوي.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'زاد المعاد في هدي خير العباد — محمد بن أبي بكر ابن قيم الجوزية', 1);
  END IF;

  -- 5) فقه الدعاء والذكر
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='bf3999e8-b660-4ea0-9cbc-d5e34664539b' AND title='فقه الدعاء والذكر: منزلة الذكر وأثره في حياة القلب') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فقه الدعاء والذكر: منزلة الذكر وأثره في حياة القلب', 'تعريف موجز بفقه الدعاء والذكر ومنزلة الذكر في حياة القلب', 'bf3999e8-b660-4ea0-9cbc-d5e34664539b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'فقه الدعاء والذكر أفرده ابن القيم في الوابل الصيب، والذكر غذاء القلب وحياته', 'فقه الدعاء والذكر باب يُعنى ببيان أحكام الذكر وآدابه ومنزلته وأثره في حياة القلب، وقد أفرد له ابن قيم الجوزية كتابه "الوابل الصيب من الكلم الطيب"، مبيّنًا أن الذكر غذاء القلب وحياته، وأن غفلة القلب عن ذكر ربه بمنزلة موته وإن كان صاحبه حيًّا ببدنه. ومن أبرز ما استُدل به على هذه المنزلة العظيمة للذكر تشبيه النبي صلى الله عليه وسلم الذاكر لربه بالحي وغير الذاكر بالميت، وهو تشبيه بليغ يبيّن أن استحضار ذكر الله هو سر حياة القلب الحقيقية لا مجرد ترديد لفظي.', 1),
    (v_lesson, 'examples', 'تشبيه النبي الذاكر بالحي وغير الذاكر بالميت', 'عن أبي موسى الأشعري رضي الله عنه أن النبي صلى الله عليه وسلم قال: «مثل الذي يذكر ربه والذي لا يذكر ربه، مثل الحي والميت» (متفق عليه، رواه البخاري 6407 ومسلم 779). وهذا الحديث هو الأصل الذي بنى عليه ابن القيم في الوابل الصيب كثيرًا من كلامه عن منزلة الذكر، مقررًا أن حياة القلب الحقيقية مرهونة بذكره لربه، وأن خلوّه من الذكر موات له وإن نبض بالحياة الحسية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الوابل الصيب من الكلم الطيب — محمد بن أبي بكر ابن قيم الجوزية', 1);
  END IF;

  -- تحديث حالة التصنيفات الخمسة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    '3db0bab4-eaa0-4000-b7f6-53c8d0e11e6f', 'f8c99ce7-6961-4a21-91d1-2688c3cc6f98',
    'de154271-d581-43fb-b57c-6f0ea5a5a1c8', 'f575aad1-4aba-4b64-9206-994b5da0b83c',
    'bf3999e8-b660-4ea0-9cbc-d5e34664539b'
  );
END $$;
